class FilterSlider extends Smooothy {
  constructor(wrapper, config = {}) {
    super(wrapper, config);

    this.wrapper = wrapper;
    this.itemsEls = [...wrapper.querySelectorAll("[data-filter-slider-item]")];
    this.createInterface(wrapper.parentNode.parentNode.querySelector(
      "[data-filter-slider-controls]"));

    this.#handleLinks();
  }

  createInterface(int) {
    const arrows = [...int.children];

    this.prevBtn = arrows[0];
    this.nextBtn = arrows[1];

    this.prevBtn.onclick = () => this.goToPrev();
    this.nextBtn.onclick = () => this.goToNext();

    this.updateArrowState();
  }

  updateArrowState() {
    if (!this.prevBtn || !this.nextBtn) return;

    let progress = gsap.utils.clamp(0, 1, this.progress ?? 0);

    if (progress < 0.1) progress = 0;
    if (progress > 0.9) progress = 1;

    this.prevBtn.classList.toggle("is--disabled", progress <= 0.1);
    this.nextBtn.classList.toggle("is--disabled", progress >= 0.9);
  }

  #handleLinks() {
    [...this.wrapper.querySelectorAll("button")].forEach((button) => {
      let startX = 0;
      let startY = 0;
      let isDragging = false;

      const handlePointerDown = (e) => {
        startX = e.clientX;
        startY = e.clientY;
        isDragging = false;
      };

      const handlePointerMove = (e) => {
        const deltaX = Math.abs(e.clientX - startX);
        const deltaY = Math.abs(e.clientY - startY);

        if (deltaX > 5 || deltaY > 5) {
          isDragging = true;
        }
      };

      const handleClick = (e) => {
        if (isDragging) {
          e.preventDefault();
          e.stopPropagation();
        }
      };

      button.addEventListener("pointerdown", handlePointerDown);
      button.addEventListener("pointermove", handlePointerMove);
      button.addEventListener("click", handleClick, true);
    });
  }

  onUpdate = () => {
    this.updateArrowState();

    const wrapRect = this.wrapper.getBoundingClientRect();
    const wrapCenter = wrapRect.left + wrapRect.width / 2;
    const maxDistance = wrapRect.width / 2;
  };

  destroy() {
    if (this.resizeObserver) {
      this.resizeObserver.disconnect();
    }

    // Nur falls Smooothy selbst ein destroy hat:
    if (super.destroy) {
      super.destroy();
    }
  }
}

