function initOnceFunctions() {
  initLenis();
  if (onceFunctionsInitialized) return;
  onceFunctionsInitialized = true;

  const resizeCallbacks = new Set();
  let resizeTimeout;

  window.addEventListener("resize", () => {
    clearTimeout(resizeTimeout);
    resizeTimeout = setTimeout(() => {
      resizeCallbacks.forEach((callback) => callback());
    }, 60);
  });

  const addResizeCallback = (callback) => {
    resizeCallbacks.add(callback);
    return () => resizeCallbacks.delete(callback);
  };

  setViewportSizes();
  addResizeCallback(() => {
    setViewportSizes();
  });

  // Runs once on first load
  // if (has('[data-something]')) initSomething();

  initAnimate();

}

function initBeforeEnterFunctions(next) {
  nextPage = next || document;

  if (document.documentElement.classList.contains("has--menu-open")) {
    document.documentElement.classList.remove("has--menu-open");
  }

  if (has("[data-background-animation]")) initBackgroundAnimation();
  if (has("[data-hero-sequence]")) initHeroSequence();
  if (has("[data-button]")) initButton();
  if (has("[data-button-alt]")) initButtonAlt();
  if (has("[data-filter-slider]")) initFilterSlider();

  // Runs before the enter animation
  // if (has('[data-something]')) initSomething();
}

function initAfterEnterFunctions(next) {
  nextPage = next || document;

  // Runs after enter animation completes
  // if (has('[data-something]')) initSomething();

  if (has("[data-call-out]")) initCallout();
  if (has("[data-handwritten-text-inview]")) initHandwrittenTextInview();
  if (has("[data-footer-parallax]")) initFooterParallax();
  if (has("[data-pop-up]")) initPopUp();
  if (has("[data-books-list-slider]")) initBooksListSlider();
  if (has("[data-books-slider]")) initBooksSlider();
  if (has("[data-exclusive-slider]")) initExclusiveSlider();
  if (has("[data-accordion]")) initAccordion();
  if (has("[data-faq-sidebar]")) initFaqSidebar();
  if (has("[data-badge")) initBadge();
  if (has("[data-benefits]")) initBenefits();
  if (has("[data-momentum-hover]")) initMomentumBasedHover();
  if (has("[data-gift]")) initGift();
  if (has("[data-tagline-curve]")) initTaglineCurve();
  if (has("[data-form-validate]")) initFormValidation();
  if (has("[data-footer-parallax]")) initFooterParallax();
  if (has("[data-genre-interaction]")) initGenreInteraction();
  if (has("[data-box-sequence]")) initBoxSequence();
  if (has("[data-plop-in]")) initPlopIn();
  if (has("[data-emoji-rain]")) initEmojiRain();
  if (has("[data-tabs]")) initTabs();
  if (has("[data-scrolling-cta]")) initScrollingCta();
  if (has("[data-search]")) initSearch();
  if (has("[data-current-month]")) initCurrentMonth();
  if (has("[data-check-contrast]")) initCheckContrast();

  initMenu();
  initDetectScrollingDirection();

  if (hasLenis) {
    lenis.resize();
  }

  if (hasScrollTrigger) {
    ScrollTrigger.refresh();
  }
}

