function runPageLeaveAnimation(current, next) {
  const transitionWrap = document.querySelector("[data-transition-wrap]");
  const transitionSVGPath = transitionWrap.querySelectorAll("svg path");
  const transitionLogo = transitionWrap.querySelectorAll("[data-transition-logo]");

  const tl = gsap.timeline({
    onComplete: () => { current.remove() }
  });

  if (reducedMotion) {
    // Immediate swap behavior if user prefers reduced motion
    return tl.set(current, { autoAlpha: 0 });
  }

  tl.set(next, {
    autoAlpha: 0,
  }, 0);

  tl.set(transitionLogo, {
    scale: 0,
    rotate: -64,
    autoAlpha: 0,
  });

  tl.set(transitionSVGPath, {
    strokeWidth: "8%",
    drawSVG: '0% 0%',
  });

  tl.to(transitionSVGPath, {
    keyframes: {
      "15%": {
        strokeWidth: "8%",
      },
      "90%": {
        drawSVG: '0% 100%',
      },
      "100%": {
        strokeWidth: "70%",
      },
    },
    duration: 1.25,
  }, "startLeave");

  tl.to(transitionLogo, {
    scale: 1,
    rotate: 0,
    autoAlpha: 1,
    delay: 0.5,
    duration: 0.65,
    ease: "elastic.out(1,0.72)",
  }, "startLeave");

  return tl;
}

