function initSearch() {
  const element = nextPage.querySelector("[data-search]");
  if (!element) return;

  const searchInput = element.querySelector("[data-search-form]");
  const searchButton = element.querySelector("[data-search-form-button]");
  const loadMoreButton = element.querySelector("[data-search-load-more]");
  const loadMoreButtonText = loadMoreButton?.querySelector("[data-search-load-more-text]");
  
  const emptyState = element.querySelector("[data-search-empty]");
  const emptyLoadMoreState = element.querySelector("[data-search-empty-load-more]");

  const filterButtons = element.querySelectorAll("[data-search-filter-button]");

  // Set this attribute on the Webflow Collection List Wrapper:
  // <div data-search-load-list class="books-list__collection w-dyn-list">
  const collection = element.querySelector("[data-search-load-list]");
  const list = collection?.querySelector(".w-dyn-items");

  const activeTags = new Set();

  let activeSearchIds = null;
  let bookData = [];
  let miniSearch = null;

  let nextPageUrl = getNextPageUrl(collection);
  let isLoadingMore = false;

  function normalize(value) {
    return value.trim().toLowerCase();
  }

  function getBooks() {
    return [...element.querySelectorAll("[data-search-target-book]")];
  }

  function getNextPageUrl(scope) {
    const nextLink = scope?.querySelector(".w-pagination-next");
    if (!nextLink) return null;

    const href = nextLink.getAttribute("href");
    if (!href) return null;

    return new URL(href, window.location.href).href;
  }

  function getPaginationParamFromHref(href) {
    if (!href) return null;

    const match = href.match(/[?&]([^=]+_page)=\d+/);
    return match ? match[1] : null;
  }

  function getNextCollection(doc) {
    const currentNextHref = collection
      ?.querySelector(".w-pagination-next")
      ?.getAttribute("href");

    const paginationParam = getPaginationParamFromHref(currentNextHref);

    if (paginationParam) {
      const collections = [...doc.querySelectorAll(".w-dyn-list")];

      const matchedCollection = collections.find((dynList) => {
        const nextHref = dynList
          .querySelector(".w-pagination-next")
          ?.getAttribute("href");

        const prevHref = dynList
          .querySelector(".w-pagination-previous")
          ?.getAttribute("href");

        return (
          nextHref?.includes(`${paginationParam}=`) ||
          prevHref?.includes(`${paginationParam}=`)
        );
      });

      if (matchedCollection) return matchedCollection;
    }

    return doc.querySelector("[data-search-load-list]");
  }

  function rebuildIndex() {
    const books = getBooks();

    bookData = books.map((book, index) => {
      const tags = [...book.querySelectorAll("[data-search-target-book-genre]")]
        .map((genre) => genre.getAttribute("data-search-target-book-genre"))
        .filter(Boolean)
        .map(normalize);

      const title =
        book.querySelector("[data-search-target-book-title]")?.textContent || "";

      return {
        id: String(index),
        element: book,
        tags,
        title,
      };
    });

    miniSearch = new MiniSearch({
      fields: ["title"],
      storeFields: ["id"],
      searchOptions: {
        prefix: true,
        fuzzy: 0.2,
        combineWith: "AND",
      },
    });

    miniSearch.addAll(bookData);
  }

  function updateSearch() {
    if (!searchInput || !miniSearch) return;

    const query = searchInput.value.trim();

    if (!query) {
      activeSearchIds = null;
    } else {
      const results = miniSearch.search(query);
      activeSearchIds = new Set(results.map((result) => result.id));
    }

    update();
  }

  function update() {
    let visibleCount = 0;
  
    bookData.forEach((book) => {
      const matchesTags =
        activeTags.size === 0 ||
        [...activeTags].every((tag) => book.tags.includes(tag));
  
      const matchesSearch =
        activeSearchIds === null || activeSearchIds.has(book.id);
  
      const isVisible = matchesTags && matchesSearch;
  
      book.element.style.display = isVisible ? "" : "none";
  
      if (isVisible) visibleCount++;
    });
  
    const hasActiveFilterOrSearch =
      activeTags.size > 0 || !!searchInput?.value.trim();
  
    if (emptyState) {
      emptyState.style.display =
        visibleCount === 0 && !nextPageUrl ? "" : "none";
    }
  
    if (emptyLoadMoreState) {
      emptyLoadMoreState.style.display =
        visibleCount === 0 && nextPageUrl && hasActiveFilterOrSearch ? "" : "none";
    }
  
    hideEmptyGroups();
    updateLoadMoreButton();
  
    requestAnimationFrame(() => {
      rebuildBookSliders();
      ScrollTrigger.refresh();
    });
  }

  function hideEmptyGroups() {
    const groups = element.querySelectorAll("[data-search-target-item]");

    groups.forEach((group) => {
      const visibleBooks = [...group.querySelectorAll("[data-search-target-book]")]
        .some((book) => book.style.display !== "none");

      group.style.display = visibleBooks ? "" : "none";
    });
  }

  function updateLoadMoreButton() {
    if (!loadMoreButton) return;
  
    const hasActiveFilterOrSearch =
      activeTags.size > 0 || !!searchInput?.value.trim();
  
    const hasVisibleBooks = bookData.some(
      (book) => book.element.style.display !== "none"
    );
  
    loadMoreButton.style.display = nextPageUrl ? "" : "none";
    loadMoreButton.disabled = isLoadingMore;
  
    if (loadMoreButtonText) {
      if (isLoadingMore) {
        loadMoreButtonText.textContent = "Loading...";
      } else if (hasActiveFilterOrSearch && !hasVisibleBooks) {
        loadMoreButtonText.textContent = "Load more results";
      } else {
        loadMoreButtonText.textContent = "Load more";
      }
    }
  }

  async function loadMore() {
    if (!nextPageUrl || isLoadingMore || !list) return;

    isLoadingMore = true;
    updateLoadMoreButton();

    try {
      const response = await fetch(nextPageUrl);
      if (!response.ok) throw new Error("Could not load next page");

      const html = await response.text();
      const nextDoc = new DOMParser().parseFromString(html, "text/html");

      const nextCollection = getNextCollection(nextDoc);
      if (!nextCollection) throw new Error("Next collection not found");

      const nextList = nextCollection.querySelector(".w-dyn-items");
      if (!nextList) throw new Error("Next list not found");

      const nextItems = [...nextList.children];

      nextItems.forEach((item) => {
        list.appendChild(item);
      });

      nextPageUrl = getNextPageUrl(nextCollection);

      rebuildIndex();

      if (searchInput?.value.trim()) {
        updateSearch();
      } else {
        update();
      }
    } catch (error) {
      console.error(error);
    } finally {
      isLoadingMore = false;
      updateLoadMoreButton();
    }
  }

  filterButtons.forEach((button) => {
    button.setAttribute("aria-pressed", "false");

    button.addEventListener("click", () => {
      const tag = button.getAttribute("data-search-filter-tag");
      if (!tag) return;

      const normalizedTag = normalize(tag);

      if (activeTags.has(normalizedTag)) {
        activeTags.delete(normalizedTag);
        button.classList.remove("is--active");
        button.setAttribute("aria-pressed", "false");
      } else {
        activeTags.add(normalizedTag);
        button.classList.add("is--active");
        button.setAttribute("aria-pressed", "true");
      }

      update();
    });
  });

  if (searchInput) {
    searchInput.addEventListener("keydown", (event) => {
      if (event.key === "Enter") {
        event.preventDefault();
        updateSearch();
      }
    });
  }

  if (searchButton) {
    searchButton.addEventListener("click", updateSearch);
  }

  if (loadMoreButton) {
    loadMoreButton.addEventListener("click", loadMore);
  }

  rebuildIndex();
  update();
}

function initScrollingCta() {
  const element = nextPage.querySelector("[data-scrolling-cta]");

  if (!element) return;

  const target = element.querySelector("[data-scrolling-cta-item]");
  const trigger = nextPage.querySelector("[data-scrolling-cta-trigger]");

  if (!target || !trigger) return;

  gsap.to(target, {
    y: "12em",
    duration: 0.8,
    ease: "energy",
    easeReverse: true,
    scrollTrigger: {
      trigger: trigger,
      start: "top 80%", // trigger kommt unten in den Viewport
      end: "bottom bottom",
      toggleActions: "play none none reverse",
    },
  });
}

function killChildTweensOf(ancestor) {
  ancestor = gsap.utils.toArray(ancestor)[0];
  gsap.globalTimeline
    .getChildren(true, true, false)
    .forEach((tween) =>
      tween
      .targets()
      .forEach((e) => e.nodeType && ancestor.contains(e) && tween.kill(e))
    )
}

function initTabs() {
  const elements = nextPage.querySelectorAll("[data-tabs]");

  if (elements.length === 0) return;

  elements.forEach((element) => {
    const tabs = Array.from(element.querySelectorAll("[data-tabs-tab]"));
    const tabPanels = Array.from(element.querySelectorAll("[data-tabs-panel]"));
    const panels = [];
    let firstTab = null;
    let lastTab = null;
    let activeIndex = -1;

    const ACTIVE_CLASS = "is--active";
    const HIDDEN_CLASS = "is--hidden";
    const INVIEW_CLASS = "is--inview";

    if (tabs.length === 0) return;

    function initContainerTabs() {
      for (let i = 0; i < tabs.length; i += 1) {
        const $tab = tabs[i];

        $tab.tabIndex = -1;
        $tab.setAttribute("aria-selected", "false");

        let controls = $tab.getAttribute("aria-controls");
        let $tabpanel = null;

        if (controls) {
          $tabpanel = element.querySelector(`#${controls}`);
        }

        if (!$tabpanel) {
          $tabpanel = tabPanels[i] || null;

          if ($tabpanel) {
            if (!$tabpanel.id) {
              const randomId = `tabs-panel-${Math.random().toString(36).slice(2, 9)}`;
              $tabpanel.id = randomId;
            }

            $tab.setAttribute("aria-controls", $tabpanel.id);
          }
        }

        panels.push($tabpanel || null);

        if (!firstTab) {
          firstTab = $tab;
        }
        lastTab = $tab;
      }

      if (activeIndex === -1 && firstTab) {
        activeIndex = 0;
      }
    }

    function setSelectedTab($currentTab) {
      const DIR_CLASSES = ["is-entering-from-right", "is-entering-from-left",
        "is-leaving-to-right", "is-leaving-to-left"
      ];

      const currentIndex = tabs.indexOf($currentTab);
      if (currentIndex === -1) return;

      const previousIndex = activeIndex;
      let direction = null;

      if (previousIndex !== -1 && previousIndex !== currentIndex) {
        direction = currentIndex > previousIndex ? "forward" : "backward";
      }

      for (let i = 0; i < tabs.length; i += 1) {
        const $tab = tabs[i];
        const $panel = panels[i];
        if (!$panel) continue;

        $panel.classList.remove(...DIR_CLASSES);

        if (i === currentIndex) {
          $tab.setAttribute("aria-selected", "true");
          $tab.classList.add(ACTIVE_CLASS);
          $tab.removeAttribute("tabindex");
          $panel.classList.remove("is-leaving-to-left", "is-leaving-to-right");
          $panel.classList.remove(HIDDEN_CLASS);
          $panel.hidden = false;
          $panel.tabIndex = 0;

          if (direction === "forward") {
            $panel.classList.add("is-entering-from-right");
          } else if (direction === "backward") {
            $panel.classList.add("is-entering-from-left");
          }

          requestAnimationFrame(() => {
            $panel.classList.add(ACTIVE_CLASS);
            requestAnimationFrame(() => {
              $panel.classList.add(INVIEW_CLASS);
            });
          });
        } else {
          $tab.setAttribute("aria-selected", "false");
          $tab.classList.remove(ACTIVE_CLASS);
          $tab.tabIndex = -1;

          if (i === previousIndex && direction) {
            const leaveClass = direction === "forward" ? "is-leaving-to-left" :
              "is-leaving-to-right";

            $panel.hidden = false;
            $panel.classList.remove(ACTIVE_CLASS, INVIEW_CLASS);
            $panel.classList.add(leaveClass);

            const onAnimEnd = (event) => {
              if (event.target !== $panel) return;

              if (!$panel.classList.contains(leaveClass)) {
                $panel.removeEventListener("animationend", onAnimEnd);
                return;
              }

              $panel.classList.add(HIDDEN_CLASS);
              $panel.hidden = true;
              $panel.tabIndex = -1;
              $panel.classList.remove(leaveClass);
              $panel.removeEventListener("animationend", onAnimEnd);
            };

            $panel.addEventListener("animationend", onAnimEnd);
          } else {
            $panel.classList.add(HIDDEN_CLASS);
            $panel.classList.remove(ACTIVE_CLASS, INVIEW_CLASS);
            $panel.hidden = true;
            $panel.tabIndex = -1;
          }
        }
      }

      activeIndex = currentIndex;
    }

    function moveFocusToTab($tab) {
      if ($tab) {
        $tab.focus();
      }
    }

    function moveFocusToPreviousTab($currentTab) {
      if ($currentTab === firstTab) {
        moveFocusToTab(lastTab);
      } else {
        const index = tabs.indexOf($currentTab);
        if (index > 0) {
          moveFocusToTab(tabs[index - 1]);
        }
      }
    }

    function moveFocusToNextTab($currentTab) {
      if ($currentTab === lastTab) {
        moveFocusToTab(firstTab);
      } else {
        const index = tabs.indexOf($currentTab);
        if (index > -1 && index < tabs.length - 1) {
          moveFocusToTab(tabs[index + 1]);
        }
      }
    }

    function onKeydown(event) {
      const $target = event.currentTarget;
      let flag = false;

      switch (event.key) {
      case "ArrowLeft":
        moveFocusToPreviousTab($target);
        flag = true;
        break;

      case "ArrowRight":
        moveFocusToNextTab($target);
        flag = true;
        break;

      case "Home":
        moveFocusToTab(firstTab);
        flag = true;
        break;

      case "End":
        moveFocusToTab(lastTab);
        flag = true;
        break;

      default:
        break;
      }

      if (flag) {
        event.stopPropagation();
        event.preventDefault();
      }
    }

    function onClick(event) {
      setSelectedTab(event.currentTarget);
    }

    function bindEvents() {
      for (let i = 0; i < tabs.length; i += 1) {
        const $tab = tabs[i];
        $tab.addEventListener("keydown", onKeydown);
        $tab.addEventListener("click", onClick);
      }
    }

    initContainerTabs();
    if (firstTab) {
      setSelectedTab(firstTab);
    }
    bindEvents();
  });
}

function initEmojiRain() {
  const elements = nextPage.querySelectorAll("[data-emoji-rain]");
  const mm = gsap.matchMedia();

  elements.forEach((element) => {
    const emojiContainer = document.querySelector("[data-emoji-rain-container]");

    if (!emojiContainer) return;

    let emojiAnimationRunning = false;
    let cleanupTimeout;

    const createRain = (emojiTypes) => {
      if (emojiAnimationRunning) return;

      emojiAnimationRunning = true;

      const emojiContainerHeight = emojiContainer.offsetHeight;
      const emojiQuantity = 40;
      const createdElements = [];

      const getRandomInt = (min, max) =>
        Math.floor(Math.random() * (max - min + 1)) + min;

      const createEmojiElement = () => {
        const emojiScale = Math.random() * 0.7 + 0.4;
        const emojiRotate = getRandomInt(-28, 28);
        const emojiDelay = 0.001 * getRandomInt(0, 1250);
        const emojiSpeed = getRandomInt(800, 1800) * 0.001;
        const emojiPosition = `${getRandomInt(0, 10)}0%`;
        const emojiClass = `choice__single-rain-emoji-image-${
          emojiTypes[Math.floor(Math.random() * emojiTypes.length)]
        }`;

        const singleEmoji = document.createElement("div");
        singleEmoji.className = "choice__single-rain-emoji is--append";
        singleEmoji.style.left = emojiPosition;

        const singleEmojiChild = document.createElement("div");
        singleEmojiChild.className = emojiClass;
        singleEmoji.appendChild(singleEmojiChild);

        emojiContainer.appendChild(singleEmoji);
        createdElements.push(singleEmoji);

        gsap.fromTo(
          singleEmoji,
          {
            y: emojiContainerHeight,
            xPercent: -50,
            rotate: 0.001,
            scale: emojiScale,
          },
          {
            y: "-110%",
            xPercent: -50,
            rotate: 0.001,
            delay: emojiDelay,
            ease: "power1.in",
            duration: emojiSpeed,
          }
        );

        gsap.fromTo(
          singleEmojiChild,
          {
            xPercent: -25,
            rotate: emojiRotate,
          },
          {
            xPercent: 25,
            rotate: -emojiRotate,
            ease: "power1.inOut",
            delay: emojiDelay,
            duration: 0.8,
            repeat: -1,
            yoyo: true,
          }
        );
      };

      Array.from({ length: emojiQuantity }).forEach(createEmojiElement);

      cleanupTimeout = setTimeout(() => {
        createdElements.forEach((el) => el.remove());
        emojiAnimationRunning = false;
      }, 2750);
    };

    mm.add(
      {
        motion: "(prefers-reduced-motion: no-preference)",
      },
      (context) => {
        const { motion } = context.conditions;

        if (!motion) return;

        const type1 = element.getAttribute("data-emoji-rain-type-1");
        const type2 = element.getAttribute("data-emoji-rain-type-2") || type1;

        const trigger = ScrollTrigger.create({
          trigger: element,
          start: "top 80%",
          onEnter: (self) => {
            if (self.direction === 1) {
              createRain([type1, type2]);
            }
          },
        });

        return () => {
          trigger.kill();
          clearTimeout(cleanupTimeout);
          gsap.killTweensOf(emojiContainer.querySelectorAll(
            ".choice__single-rain-emoji, .choice__single-rain-emoji > div"));
          emojiContainer
            .querySelectorAll(".choice__single-rain-emoji.is--append")
            .forEach((el) => el.remove());
          emojiAnimationRunning = false;
        };
      }
    );
  });
}

function initPlopIn() {
  const elements = nextPage.querySelectorAll("[data-plop-in]");
  const mm = gsap.matchMedia();

  elements.forEach((element) => {
    const item = element.querySelector("[data-plop-in-item]");

    if (!item) return;

    mm.add(
      {
        motion: "(prefers-reduced-motion: no-preference)",
        mobile: "(max-width: 990px)",
      },
      (context) => {
        const { motion, mobile } = context.conditions;

        if (!motion) return;

        gsap.set(item, {
          scale: 0,
          rotate: -20,
          y: "-4em",
        });

        const tl = gsap.timeline({ paused: true });

        tl.to(
          item,
          {
            scale: 1,
            y: "0em",
            rotate: 11,
            duration: 0.7,
            ease: "elastic.out(1, 0.72)",
          }
        )

        const trigger = ScrollTrigger.create({
          trigger: element,
          start: "top 80%",
          end: "bottom top",
          onEnter: () => tl.play(),
        });

        return () => {
          trigger.kill();
          tl.kill();
        };
      }
    );
  });
}

let boxSequenceDestroyFns = [];

function destroyBoxSequence() {
  boxSequenceDestroyFns.forEach((fn) => fn());
  boxSequenceDestroyFns = [];
}

function initBoxSequence() {
  boxSequenceDestroyFns = [];

  const wraps = nextPage.querySelectorAll('[data-box-sequence]');

  wraps.forEach((wrap) => {
    if (wrap.dataset.sequenceInit === 'true') return;
    wrap.dataset.sequenceInit = 'true';

    let isDestroyed = false;

    const element = wrap.querySelector('[data-box-sequence-element]');
    const canvas = element && element.querySelector('[data-box-sequence-canvas]');
    const text = wrap.querySelector('[data-box-sequence-handwritten-text]');
    const title = wrap.querySelector('[data-box-sequence-title]');
    const finalText = wrap.querySelector('[data-box-sequence-text-final]');
    const buttons = wrap.querySelectorAll('[data-box-sequence-button]');
    const isShort = wrap.hasAttribute('data-box-sequence-short');

    if (!element || !canvas) return;

    const frames = parseInt(canvas.dataset.frames, 10) || 1;
    const digits = parseInt(canvas.dataset.digits, 10) || 3;
    const indexStart = parseInt(canvas.dataset.indexStart, 10) || 0;
    const desktopSrc = canvas.dataset.desktopSrc || '';
    const mobileSrc = canvas.dataset.mobileSrc || desktopSrc;
    const staticSrc = canvas.dataset.staticSrc;
    const filetype = canvas.dataset.filetype || 'webp';
    const startTrigger = wrap.dataset.scrollStart || 'top top';
    const endTrigger = wrap.dataset.scrollEnd || 'bottom top';
    const finalTextProgress = parseFloat(canvas.dataset.finalTextProgress || wrap.dataset.finalTextProgress);
    const finalTextThreshold = Number.isFinite(finalTextProgress) ? finalTextProgress : 0.81;
    const reduceMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

    const isMobile = window.matchMedia('(max-width: 767px)').matches;
    const baseUrl = isMobile ? mobileSrc : desktopSrc;
    const lastIndex = indexStart + frames - 1;

    let lastProgress = 0;
    let resizeTimer;
    let lastWindowWidth = window.innerWidth;

    const ctx = canvas.getContext('2d');

    function resizeCanvas() {
      const dpr = window.devicePixelRatio || 1;
      const width = element.clientWidth;
      const height = element.clientHeight;

      if (canvas.width !== width * dpr || canvas.height !== height * dpr) {
        canvas.width = width * dpr;
        canvas.height = height * dpr;
        canvas.style.width = `${width}px`;
        canvas.style.height = `${height}px`;
      }
    }

    function drawCover(img) {
      if (!img || isDestroyed) return;

      const canvasWidth = canvas.width;
      const canvasHeight = canvas.height;
      const scale = Math.max(canvasWidth / img.width, canvasHeight / img.height);
      const x = (canvasWidth - img.width * scale) / 2;
      const y = (canvasHeight - img.height * scale) / 2;

      ctx.clearRect(0, 0, canvasWidth, canvasHeight);
      ctx.drawImage(img, x, y, img.width * scale, img.height * scale);
    }

    function handleResize() {
      if (isDestroyed) return;

      const newWidth = window.innerWidth;
      const widthChanged = newWidth !== lastWindowWidth;

      if (!widthChanged) return;

      lastWindowWidth = newWidth;

      clearTimeout(resizeTimer);
      resizeTimer = setTimeout(() => {
        if (isDestroyed) return;

        resizeCanvas();
        if (loaded.size) render(lastProgress);
        ScrollTrigger.refresh();
      }, 200);
    }

    function pad(num) {
      return String(num).padStart(digits, '0');
    }

    function getUrl(i) {
      return `${baseUrl}${pad(i)}.${filetype}`;
    }

    const loaded = new Map();
    const loading = new Set();
    const queue = [];
    let processingQueue = false;

    function loadFrame(i, onDone) {
      if (isDestroyed) return;
      if (loaded.has(i) || loading.has(i) || i < indexStart || i > lastIndex) return;

      const url = getUrl(i);
      loading.add(i);

      (async () => {
        try {
          if (isDestroyed) return;

          const res = await fetch(url);
          if (!res.ok) throw new Error(`HTTP ${res.status}`);

          if (isDestroyed) return;

          const blob = await res.blob();
          let asset;

          if (window.createImageBitmap) {
            asset = await createImageBitmap(blob, {
              imageOrientation: 'from-image'
            });
          } else {
            const img = new Image();
            const objectUrl = URL.createObjectURL(blob);

            try {
              img.src = objectUrl;

              if (img.decode) {
                await img.decode();
              } else {
                await new Promise((resolve, reject) => {
                  img.onload = resolve;
                  img.onerror = reject;
                });
              }

              asset = img;
            } finally {
              URL.revokeObjectURL(objectUrl);
            }
          }

          if (isDestroyed) return;

          loaded.set(i, asset);

          if (typeof onDone === 'function') onDone();
        } catch (error) {
          if (!isDestroyed) {
            console.warn('[ImageSequence] Failed to load frame', {
              index: i,
              url,
              wrap,
              error
            });
          }
        } finally {
          loading.delete(i);
        }
      })();
    }

    function processQueue() {
      if (isDestroyed || processingQueue) return;

      const next = queue.shift();
      if (!next) return;

      processingQueue = true;

      const [a, b] = next;

      if (b - a <= 1) {
        processingQueue = false;
        processQueue();
        return;
      }

      const m = Math.floor((a + b) / 2);

      loadFrame(m, () => {
        if (isDestroyed) return;

        queue.push([a, m], [m, b]);
        processingQueue = false;
        setTimeout(processQueue, 0);
      });
    }

    function startLoading() {
      loadFrame(indexStart, () => {
        if (isDestroyed) return;

        drawImageAt(indexStart);
        loadFrame(lastIndex);
        queue.push([indexStart, lastIndex]);
        processQueue();
        ScrollTrigger.refresh();
      });
    }

    function findNearestLoaded(i) {
      for (let r = 1; r <= 10; r++) {
        if (loaded.has(i - r)) return i - r;
        if (loaded.has(i + r)) return i + r;
      }

      const keys = Array.from(loaded.keys());
      if (keys.length === 0) return null;

      let nearest = keys[0];
      let minDiff = Math.abs(i - nearest);

      for (const k of keys) {
        const diff = Math.abs(i - k);

        if (diff < minDiff) {
          nearest = k;
          minDiff = diff;
        }
      }

      return nearest;
    }

    function drawImageAt(i) {
      if (isDestroyed) return;

      const img = loaded.get(i);
      if (!img) return;

      drawCover(img);
    }

    function render(progress) {
      if (isDestroyed) return;

      const relative = progress * (frames - 1);
      const index = indexStart + Math.round(relative);

      if (loaded.has(index)) {
        drawImageAt(index);
      } else {
        const nearest = findNearestLoaded(index);
        if (nearest !== null) drawImageAt(nearest);
      }
    }

    resizeCanvas();
    window.addEventListener('resize', handleResize);

    const tl = gsap.timeline({ paused: true });

    if (text) {
      const textSplit = new SplitText(text, {
        type: 'words, chars',
        tag: 'span',
        charsClass: 'split-char',
        wordsClass: 'split-word'
      });

      gsap.set(textSplit.words, { display: 'inline-block' });
      gsap.set(textSplit.chars, {
        display: 'inline-block',
        opacity: 0,
        rotate: 22,
        x: '-0.25em',
        y: '0.5em'
      });

      tl.to(textSplit.chars, {
        opacity: 1,
        rotate: 0,
        x: '0em',
        y: '0em',
        ease: 'elastic.out(1, 0.75)',
        duration: 0.625,
        stagger: 0.011
      });
    }

    const finalTimeline = gsap.timeline({ paused: true });

    if (finalText) {
      const finalTextSplit = new SplitText(finalText, {
        type: 'words, chars',
        tag: 'span',
        charsClass: 'split-char',
        wordsClass: 'split-word'
      });

      gsap.set(finalTextSplit.words, { display: 'inline-block' });
      gsap.set(finalTextSplit.chars, {
        display: 'inline-block',
        opacity: 0,
        rotate: 22,
        x: '-0.25em',
        y: '0.5em'
      });

      finalTimeline.to(finalTextSplit.chars, {
        opacity: 1,
        rotate: 0,
        x: '0em',
        y: '0em',
        ease: 'elastic.out(1, 0.75)',
        duration: 0.625,
        stagger: 0.011
      }, 'start');
    }

    if (title) {
      gsap.set(title, {
        opacity: 0,
        y: '1em'
      });

      finalTimeline.to(title, {
        opacity: 1,
        y: '0em',
        ease: 'elastic.out(1, 0.75)',
        duration: 0.625
      }, 'start');
    }

    if (buttons.length) {
      gsap.set(buttons, {
        rotate: gsap.utils.random(-16, 16),
        scale: 0
      });

      finalTimeline.to(buttons, {
        rotate: 0,
        scale: 1,
        ease: 'elastic.out(1, 0.75)',
        duration: 0.625,
        stagger: 0.026
      }, 'start+=0.15');
    }

    boxSequenceDestroyFns.push(() => {
      isDestroyed = true;

      window.removeEventListener('resize', handleResize);
      clearTimeout(resizeTimer);

      loaded.clear();
      loading.clear();
      queue.length = 0;

      tl.kill();
      finalTimeline.kill();

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      delete wrap.dataset.sequenceInit;
    });

    if (reduceMotion) {
      if (staticSrc) {
        const staticImage = new Image();

        staticImage.src = staticSrc;
        staticImage.onload = () => {
          if (!isDestroyed) drawCover(staticImage);
        };

        staticImage.onerror = () => {};
        return;
      }

      loadFrame(indexStart, () => {
        drawImageAt(indexStart);
      });

      return;
    }

    startLoading();
    
    let textState = 'before';
    let finalState = 'before';

    const st = ScrollTrigger.create({
      trigger: wrap,
      start: startTrigger,
      end: endTrigger,
      scrub: true,
      onUpdate: (self) => {
        if (isDestroyed) return;

        lastProgress = self.progress;
        render(self.progress);

        if (self.progress >= 0.6) {
          if (textState !== 'reversed') {
            tl.timeScale(3.5).reverse();
            textState = 'reversed';
          }
        } else if (self.progress >= 0.3) {
          if (textState !== 'played') {
            tl.timeScale(1.5).play();
            textState = 'played';
          }
        } else {
          if (textState !== 'before') {
            tl.timeScale(3.5).reverse();
            textState = 'before';
          }
        }

        if (self.progress >= finalTextThreshold) {
          if (finalState !== 'played') {
            finalTimeline.timeScale(1.25).play();
            finalState = 'played';
          }
        } else {
          if (finalState !== 'before') {
            finalTimeline.timeScale(3.5).reverse();
            finalState = 'before';
          }
        }
      }
    });

    lastProgress = st.progress || 0;
    render(lastProgress);

    const mm = gsap.matchMedia();

    mm.add('(min-width: 992px)', () => {
      if (!isShort) createScrollAnim(-25);
      if (isShort) createScrollAnim(0);
    });

    mm.add('(max-width: 991px)', () => {
      if (!isShort) createScrollAnim(-50);
      if (isShort) createScrollAnim(0);
    });

    function createScrollAnim(startY) {
      gsap.to(canvas, {
        keyframes: [
          { yPercent: startY, duration: 0 },
          { yPercent: 0, duration: 0.25 },
          { yPercent: 0, duration: 0.75 }
        ],
        ease: 'none',
        scrollTrigger: {
          trigger: wrap,
          start: startTrigger,
          end: endTrigger,
          scrub: true
        }
      });
    }
  });
}

