function initMomentumBasedHover() {

  // If this device can’t hover with a fine pointer, stop here
  if (!window.matchMedia("(hover: hover) and (pointer: fine)").matches) { return; }

  // Configuration (tweak these for feel)
  const xyMultiplier = 25; // multiplies pointer velocity for x/y movement
  const rotationMultiplier = 15; // multiplies normalized torque for rotation speed
  const inertiaResistance = 160; // higher = stops sooner

  // Pre-build clamp functions for performance
  const clampXY = gsap.utils.clamp(-1080, 1080);
  const clampRot = gsap.utils.clamp(-60, 60);

  // Initialize each root container
  nextPage.querySelectorAll('[data-momentum-hover]').forEach(root => {
    let prevX = 0,
      prevY = 0;
    let velX = 0,
      velY = 0;
    let rafId = null;

    // Track pointer velocity (throttled to RAF)
    root.addEventListener('mousemove', e => {
      if (rafId) return;
      rafId = requestAnimationFrame(() => {
        velX = e.clientX - prevX;
        velY = e.clientY - prevY;
        prevX = e.clientX;
        prevY = e.clientY;
        rafId = null;
      });
    });

    // Attach hover inertia to each child element
    root.querySelectorAll('[data-momentum-hover-element]').forEach(el => {
      el.addEventListener('mouseenter', e => {
        const target = el.querySelector('[data-momentum-hover-target]');
        if (!target) return;

        // Compute offset from center to pointer
        const { left, top, width, height } = target.getBoundingClientRect();
        const centerX = left + width / 2;
        const centerY = top + height / 2;
        const offsetX = e.clientX - centerX;
        const offsetY = e.clientY - centerY;

        // Compute raw torque (px²/frame)
        const rawTorque = offsetX * velY - offsetY * velX;

        // Normalize torque so rotation ∝ pointer speed (deg/sec)
        const leverDist = Math.hypot(offsetX, offsetY) || 1;
        const angularForce = rawTorque / leverDist;

        // Calculate and clamp velocities
        const velocityX = clampXY(velX * xyMultiplier);
        const velocityY = clampXY(velY * xyMultiplier);
        const rotationVelocity = clampRot(angularForce * rotationMultiplier);

        // Apply GSAP inertia tween
        gsap.to(target, {
          inertia: {
            x: { velocity: velocityX, end: 0 },
            y: { velocity: velocityY, end: 0 },
            rotation: { velocity: rotationVelocity, end: 0 },
            resistance: inertiaResistance
          }
        });
      });
    });
  });
}

function initBadge() {
  const elements = nextPage.querySelectorAll("[data-badge]");
  const mm = gsap.matchMedia();

  elements.forEach((element) => {
    const items = element.querySelectorAll("[data-badge-item]");
    const [item1, item2] = items;

    if (!item1 || !item2) return;

    mm.add(
      {
        motion: "(prefers-reduced-motion: no-preference)",
        mobile: "(max-width: 990px)",
      },
      (context) => {
        const { motion, mobile } = context.conditions;

        if (!motion) return;

        const item2Y = mobile ? "-0.25em" : "-1em";

        gsap.set(item1, {
          rotate: -2,
          y: "-2em",
        });

        gsap.set(item2, {
          rotate: 1,
          y: "-6em",
        });

        const tl = gsap.timeline({ paused: true });

        tl.to(
          item1,
          {
            y: "0em",
            rotate: 0,
            duration: 1,
            ease: "elastic.out(1, 0.75)",
          },
          0
        ).to(
          item2,
          {
            y: item2Y,
            rotate: -4.7,
            duration: 1,
            ease: "elastic.out(1, 0.75)",
          },
          0.0088
        );

        const trigger = ScrollTrigger.create({
          trigger: element,
          start: "top 80%",
          end: "bottom top",
          onEnter: () => tl.play(),
        });

        return () => {
          trigger.kill();
          tl.kill();
        };
      }
    );
  });
}

function initFaqSidebar() {
  const sidebars = [...nextPage.querySelectorAll("[data-faq-sidebar]")];
  if (sidebars.length === 0) return;

  const links = sidebars.flatMap((sb) => [...sb.querySelectorAll("[data-faq-sidebar-link]")]);
  if (links.length === 0) return;

  const pairs = links.map((link) => {
    const id = link.getAttribute("data-faq-sidebar-link");
    const target = nextPage.querySelector(`[data-faq-section="${id}"]`);
    return target ? { link, target, id } : null;
  }).filter(Boolean);

  if (pairs.length === 0) return;

  const ACTIVE_CLASS = "is--active";
  const HEADER_OFFSET = 96;

  const setActive = (slug) => {
    links.forEach((link) => {
      link.classList.toggle(ACTIVE_CLASS, link.getAttribute("data-faq-sidebar-link") ===
        slug);
    });
  };

  pairs.forEach(({ link, target, id }) => {
    link.addEventListener("click", (e) => {
      e.preventDefault();
      history.replaceState(null, "", `#${id}`);
      lenis.scrollTo(target, {
        offset: -HEADER_OFFSET,
        duration: 1.1,
        lock: true,
      });
    });
  });

  pairs.forEach(({ target, id }) =>
    ScrollTrigger.create({
      trigger: target,
      start: `top ${HEADER_OFFSET + 40}px`,
      end: `bottom ${HEADER_OFFSET + 40}px`,
      onToggle: ({ isActive }) => {
        if (isActive) setActive(id);
      },
      onEnter: () => setActive(id),
      onEnterBack: () => setActive(id),
    })
  );
}

