function initAccordion() {
  const elements = nextPage.querySelectorAll("[data-accordion]");

  if (elements.length === 0) return;

  elements.forEach((element) => {
    const summary = element.querySelector("[data-accordion-summary]");
    const content = element.querySelector("[data-accordion-content]");

    if (!summary || !content) return;

    let animation = null;
    let isClosing = false;
    let isExpanding = false;

    let duration = 450;
    if (window.isReducedMotion) duration = 0;

    const easing = "cubic-bezier(.32, .72, 0, 1)";
    const activeClass = "is--active";

    function onClick(e) {
      e.preventDefault();
      element.style.overflowY = "clip";

      if (isClosing || !element.open) {
        open();
      } else if (isExpanding || element.open) {
        shrink();
      }
    }

    function open() {
      element.style.height = `${element.offsetHeight}px`;
      element.open = true;

      requestAnimationFrame(expand);
    }

    function expand() {
      isExpanding = true;
      element.classList.add(activeClass);

      const startHeight = `${element.offsetHeight}px`;
      const endHeight = `${summary.offsetHeight + content.offsetHeight}px`;

      if (animation) animation.cancel();

      animation = element.animate({ height: [startHeight, endHeight] }, { duration, easing });

      animation.onfinish = () => onAnimationFinish(true);
      animation.oncancel = () => {
        isExpanding = false;
        element.classList.remove(activeClass);
      };
    }

    function shrink() {
      isClosing = true;
      element.classList.remove(activeClass);

      const startHeight = `${element.offsetHeight}px`;
      const endHeight = `${summary.offsetHeight}px`;

      if (animation) animation.cancel();

      animation = element.animate({ height: [startHeight, endHeight] }, { duration, easing });

      animation.onfinish = () => onAnimationFinish(false);
      animation.oncancel = () => {
        isClosing = false;
        element.classList.add(activeClass);
      };
    }

    function onAnimationFinish(open) {
      element.open = open;
      animation = null;
      isClosing = false;
      isExpanding = false;
      element.style.height = "";
      element.style.overflow = "";
    }

    summary.addEventListener("click", onClick);
  });
}

const rafs = [];
const booksSliderMM = gsap.matchMedia();
const exclusiveSliderMM = gsap.matchMedia();
const booksListSliderMM = gsap.matchMedia();
const filterSliderMM = gsap.matchMedia();
let isDesktopSlider = false;

function initBooksSlider() {
  booksSliderMM.add("(min-width: 992px)", () => {
    const elements = nextPage.querySelectorAll("[data-books-slider]");
    const instances = [];

    elements.forEach((element) => {
      const sliderWrapper = element.querySelector("[data-books-slider-wrapper]");
      if (!sliderWrapper) return;

      const slider = new ParallaxSlider(sliderWrapper, {
        infinite: false,
        snap: false,
        dragSensitivity: 0.008,
        lerpFactor: 0.225,
        scrollSensitivity: 1,
        bounceLimit: 0.5,
        setOffset: ({ itemWidth, wrapperWidth }) => {
          return wrapperWidth - 32;
        },
      });

      const rafFn = () => slider.update();
      rafs.push(rafFn);

      instances.push({ slider, rafFn });
    });

    return () => {
      instances.forEach(({ slider, rafFn }) => {
        const index = rafs.indexOf(rafFn);
        if (index !== -1) rafs.splice(index, 1);

        if (typeof slider.destroy === "function") {
          slider.destroy();
        }

        if (typeof slider.cleanup === "function") {
          slider.cleanup();
        }
      });
    };
  });
}

