const bookSliders = new Map();

function getVisibleSliderItems(wrapper) {
  return [...wrapper.querySelectorAll("[data-books-list-slider-item]")]
    .filter((item) => item.offsetParent !== null);
}

function needsSlider(wrapper) {
  const visibleItems = getVisibleSliderItems(wrapper);

  if (visibleItems.length <= 1) return false;

  const totalWidth = visibleItems.reduce((sum, item) => {
    return sum + item.getBoundingClientRect().width;
  }, 0);

  return totalWidth > wrapper.getBoundingClientRect().width;
}

function rebuildBookSliders() {
  if (!isDesktopSlider) return;

  nextPage.querySelectorAll("[data-books-list-slider]").forEach((element) => {
    const wrapper = element.querySelector("[data-books-list-slider-wrapper]");
    const controls = element.querySelector("[data-books-list-slider-controls]");
    if (!wrapper) return;

    const existing = bookSliders.get(wrapper);

    if (existing) {
      const index = rafs.indexOf(existing.rafFn);
      if (index !== -1) rafs.splice(index, 1);

      existing.slider.destroy?.();
      existing.slider.cleanup?.();

      bookSliders.delete(wrapper);
    }

    const shouldSlide = needsSlider(wrapper);

    if (controls) {
      controls.style.display = shouldSlide ? "" : "none";
    }

    wrapper.classList.toggle("is-slider-disabled", !shouldSlide);

    if (!shouldSlide) {
      wrapper.style.transform = "";
      return;
    }

    const slider = new Slider(wrapper, {
      infinite: false,
      snap: false,
      dragSensitivity: 0.008,
      lerpFactor: 0.225,
      scrollSensitivity: 1,
      bounceLimit: 0.5,
      setOffset: ({ wrapperWidth }) => {
        return wrapperWidth - 112;
      },
    });

    const rafFn = () => slider.update();
    rafs.push(rafFn);

    bookSliders.set(wrapper, { slider, rafFn });
  });
}

function initBooksListSlider() {
  booksListSliderMM.add("(min-width: 992px)", () => {
    isDesktopSlider = true;

    rebuildBookSliders();

    return () => {
      isDesktopSlider = false;

      bookSliders.forEach(({ slider, rafFn }) => {
        const index = rafs.indexOf(rafFn);

        if (index !== -1) {
          rafs.splice(index, 1);
        }

        slider.destroy?.();
        slider.cleanup?.();
      });

      bookSliders.clear();
    };
  });
}

