function initFooterParallax() {
  const mm = gsap.matchMedia();

  mm.add("(min-width: 991px)", () => {
    nextPage.querySelectorAll("[data-footer-parallax]").forEach(el => {
      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: el,
          start: "clamp(top bottom)",
          end: "clamp(top top)",
          scrub: 0.2,
        }
      });

      const top = el.querySelector("[data-footer-parallax-top]");
      const bottom = el.querySelector("[data-footer-parallax-bottom]");
      const visual = el.querySelector("[data-footer-parallax-visual]");
      const overlay = el.querySelector("[data-footer-parallax-overlay]");

      if (top) {
        tl.fromTo(top, {
          y: "-12.5em",
        }, {
          y: "0em",
          ease: "none",
        });
      }

      if (bottom) {
        tl.fromTo(bottom, {
          y: "-12.5em",
        }, {
          y: "0em",
          ease: "none",
        }, "<");
      }

      if (visual) {
        tl.fromTo(visual, {
          scale: 0.9,
          xPercent: -35,
          y: "17.5em",
          rotate: 30,
        }, {
          scale: 1,
          xPercent: 0,
          y: "0em",
          rotate: 0,
          ease: "none",
        }, "<");
      }

      if (overlay) {
        tl.fromTo(overlay, {
          opacity: 0.55,
        }, {
          opacity: 0,
          ease: "none",
        }, "<");
      }
    });
  });
}

function initPopUp() {
  nextPage.querySelectorAll("[data-pop-up]").forEach((el) => {
    const button = el.querySelector("[data-pop-up-button]");
    if (!button) return;

    let lockedOpen = false;

    const open = () => el.classList.add("is--open");
    const close = () => el.classList.remove("is--open");

    el.addEventListener("pointerenter", () => {
      if (!lockedOpen) open();
    });

    el.addEventListener("pointerleave", () => {
      if (!lockedOpen) close();
    });

    button.addEventListener("click", (e) => {
      e.preventDefault();
      lockedOpen = !lockedOpen;
      el.classList.toggle("is--open", lockedOpen);
    });
  });
}

function initCheckContrast() {
  nextPage.querySelectorAll("[data-check-contrast]").forEach((wrapper) => {
    const bg = wrapper.querySelector("[data-check-contrast-bg]");
    const texts = wrapper.querySelectorAll("[data-check-contrast-text]");

    if (!bg || !texts.length) return;

    const bgColor = getComputedStyle(bg).backgroundColor;
    const rgb = bgColor.match(/\d+/g)?.map(Number);

    if (!rgb || rgb.length < 3) return;

    const [r, g, b] = rgb;

    // Relative Helligkeit
    const luminance = (0.299 * r + 0.587 * g + 0.114 * b) / 255;

    const textColor = luminance > 0.5 ? "#000" : "#fff";

    texts.forEach((text) => {
      text.style.color = textColor;
    });
  });
}

